import React, { useEffect } from 'react';
import { X } from 'lucide-react';

const EditModal = ({ show, onClose }) => {
  console.log('EditModal props - show:', show, 'onClose type:', typeof onClose);

  const testClose = () => {
    console.log('Test close button clicked!');
    alert('Test close clicked!');
    if (onClose) {
      onClose();
    } else {
      console.error('onClose is not defined!');
    }
  };

  useEffect(() => {
    const handleEscape = (e) => {
      if (e.key === 'Escape') {
        onClose();
      }
    };
    if (show) {
      document.addEventListener('keydown', handleEscape);
    }
    return () => document.removeEventListener('keydown', handleEscape);
  }, [show, onClose]);

  if (!show) return null;

  return (
    <div 
      className="fixed inset-0 bg-black/50 flex items-center justify-center z-50"
      onClick={onClose}
    >
      <div 
        className="bg-white rounded-xl p-6 max-w-md w-full mx-4"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-bold">Edit Course</h2>
          <button 
            onClick={testClose}
            className="bg-red-500 text-white p-3 rounded-full hover:bg-red-600 text-lg font-bold"
          >
            ✕
          </button>
        </div>
        <p className="mb-4">Modal test - multiple ways to close:</p>
        <div className="space-y-2">
          <button 
            onClick={onClose}
            className="w-full bg-red-600 text-white py-3 rounded-lg hover:bg-red-700 font-bold text-lg"
          >
            CLOSE MODAL
          </button>
          <button 
            onClick={onClose}
            className="w-full bg-gray-500 text-white py-2 rounded hover:bg-gray-600"
          >
            Cancel
          </button>
          <p className="text-sm text-gray-600 text-center">
            Also try: Click outside, press Escape, or click X
          </p>
        </div>
      </div>
    </div>
  );
};

export default EditModal;
